// Build Slack Block Kit payload from input
const input = $input.first().json;

const isSuccess = !!input.isSuccess;
const status = input.status || 'unknown';
const channel = input.channel || 'unknown';
const command = input.command || 'N/A';
const duration = input.duration ? `${input.duration}s` : 'N/A';
const youtubeId = input.youtubeId || null;
const errorMessage = input.errorMessage || null;
const source = input.source || 'pipeline';
const outputUrl = input.outputUrl || null;
const timedOut = !!input.timedOut;
const pollCount = input.pollCount || null;

const capitalize = (s) => s ? s.charAt(0).toUpperCase() + s.slice(1) : '';

// Status emoji
const emoji = isSuccess ? '✅' : timedOut ? '⏰' : '❌';
const statusLabel = timedOut ? 'Timed Out' : capitalize(status);

// Header
const headerText = `${emoji} ${capitalize(source)} ${statusLabel} — ${capitalize(channel)}`;

// Fields
const fields = [
  { type: 'mrkdwn', text: `*Channel:*\n${channel}` },
  { type: 'mrkdwn', text: `*Command:*\n${command}` },
  { type: 'mrkdwn', text: `*Duration:*\n${duration}` },
  { type: 'mrkdwn', text: `*Source:*\n${source}` }
];

if (youtubeId) {
  fields.push({ type: 'mrkdwn', text: `*YouTube ID:*\n${youtubeId}` });
}
if (outputUrl) {
  fields.push({ type: 'mrkdwn', text: `*Output:*\n${outputUrl}` });
}
if (pollCount) {
  fields.push({ type: 'mrkdwn', text: `*Polls:*\n${pollCount}` });
}

const blocks = [
  {
    type: 'header',
    text: { type: 'plain_text', text: headerText }
  },
  {
    type: 'section',
    fields: fields
  }
];

// Add error context block if failed
if (!isSuccess && errorMessage) {
  blocks.push({
    type: 'section',
    text: { type: 'mrkdwn', text: `*Error:*\n\`\`\`${errorMessage.substring(0, 500)}\`\`\`` }
  });
}

return {
  text: `${emoji} ${capitalize(source)} ${statusLabel} — ${capitalize(channel)}`,
  blocks: blocks
};

// Return notification result back to calling workflow
const trigger = $('Execute Workflow Trigger').first().json;
return {
  notified: true,
  channel: trigger.channel || 'unknown'
};
